      .from(entityProposals)
      .where(and(eq(entityProposals.id, proposalId), eq(entityProposals.status, 'pending')))
      .limit(1);
    if (!proposal) throw new Error('Entity proposal not found or already reviewed');

    await tx
      .update(entityProposals)
      .set({
        status: 'rejected',
        reviewedByEmployeeId: me.id,
        reviewedAt: new Date(),
      })
      .where(eq(entityProposals.id, proposalId));

    await tx.insert(taxonomyChangeLog).values({
      changeType: 'reject_entity_proposal',
      beforeState: {
        proposalId,
        proposedEntityType: proposal.proposedEntityType,
        proposedCanonicalValue: proposal.proposedCanonicalValue,
      },
      afterState: null,
      reason,
      approvedByEmployeeId: me.id,
    });
  });

  revalidatePath('/admin/taxonomy/entity-proposals');
  revalidatePath('/admin/taxonomy/change-log');
}

export async function approveEntityProposal(
  proposalId: string,
  // Allow the admin to refine the canonical value at approval time.
  finalCanonicalValue?: string,
  // Optional display label (defaults to canonical value).
  displayLabel?: string,
) {
  const me = await requireAdmin();
  const db = getDirectDb();

  await db.transaction(async (tx) => {
    const [proposal] = await tx
      .select()
      .from(entityProposals)
      .where(and(eq(entityProposals.id, proposalId), eq(entityProposals.status, 'pending')))
      .limit(1);
    if (!proposal) throw new Error('Entity proposal not found or already reviewed');

    const canonicalValue = (finalCanonicalValue ?? proposal.proposedCanonicalValue).trim();
    if (!canonicalValue) {
      throw new Error('canonical value must not be empty');
    }

    const aliases = Array.isArray(proposal.rawStringsObserved)
      ? (proposal.rawStringsObserved as string[]).filter((s) => s && s !== canonicalValue)
      : [];

    const [insertedEntity] = await tx
      .insert(entities)
      .values({
        entityType: proposal.proposedEntityType,
        canonicalValue,
        displayLabel: displayLabel ?? canonicalValue,
        aliases,
        domainHints: proposal.proposedDomainHints ?? [],
      })
      .onConflictDoNothing()
      .returning({ id: entities.id });

    // If onConflictDoNothing returned no row, that means an entity with the
    // same (entity_type, canonical_value) already exists. Look it up so we
    // can merge against it instead of creating a duplicate.
    let entityId = insertedEntity?.id;
    if (!entityId) {
      const [existing] = await tx
        .select({ id: entities.id })
        .from(entities)
        .where(
          and(
            eq(entities.entityType, proposal.proposedEntityType),
            eq(entities.canonicalValue, canonicalValue),
          ),
        )
        .limit(1);
      if (!existing) throw new Error('failed to resolve entity after onConflictDoNothing');
      entityId = existing.id;
    }

    await tx
      .update(entityProposals)
      .set({
        status: insertedEntity ? 'approved' : 'merged_into_existing',
        mergedIntoEntityId: entityId,
        reviewedByEmployeeId: me.id,
        reviewedAt: new Date(),
      })
      .where(eq(entityProposals.id, proposalId));

    await tx.insert(taxonomyChangeLog).values({
      changeType: insertedEntity ? 'create_entity_from_proposal' : 'merge_entity_proposal',
      beforeState: {
        proposalId,
        proposedEntityType: proposal.proposedEntityType,
        proposedCanonicalValue: proposal.proposedCanonicalValue,
      },
      afterState: { entityId, finalCanonicalValue: canonicalValue },
      reason: null,
      approvedByEmployeeId: me.id,
    });
  });

  revalidatePath('/admin/taxonomy/entity-proposals');
  revalidatePath('/admin/taxonomy/entities');
  revalidatePath('/admin/taxonomy/change-log');
}

// R10 — Extraction candidate review dashboard.
//
// Reads from extraction_candidates + extraction_validation_results.
// Lets the admin filter by status and drill into the validation reason
// for failed / sensitive candidates without exposing raw evidence text
// to the standard queue (sensitive candidates stay hidden by default).

export const dynamic = 'force-dynamic';

import { sql } from 'drizzle-orm';
import { getDirectDb } from '@oracle/db/client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { MetricCard } from '../_components/metric-card';

type CandidateRow = {
  id: string;
  status: string;
  claim_type: string;
  summary: string;
  impact_score: number;
  confidence_score: number | null;
  domains: unknown;
  stance: string | null;
  requires_review: boolean;
  review_reason: string | null;
  validation_error: string | null;
  promoted_to_claim_id: string | null;
  duplicate_of_claim_id: string | null;
  created_at: string;
  validated_at: string | null;
  promoted_at: string | null;
  validation_failures: number;
};

type StatusCountRow = { status: string; count: number };

function statusBadge(status: string) {
  const map: Record<string, string> = {
    pending_validation: 'bg-yellow-100 text-yellow-800',
    validated: 'bg-blue-100 text-blue-800',
    promoted: 'bg-green-100 text-green-800',
    duplicate: 'bg-gray-100 text-gray-700',
    validation_failed: 'bg-red-100 text-red-800',
    failed_validation_loop: 'bg-red-200 text-red-900',
    rejected: 'bg-gray-100 text-gray-600',
    rejected_sensitive: 'bg-purple-100 text-purple-800',
    quarantined_sensitive: 'bg-purple-200 text-purple-900',
  };
  return map[status] ?? 'bg-muted';
}

export default async function AdminAICandidatesPage({
  searchParams,
}: {
  searchParams: Promise<{ status?: string }>;
}) {
  const params = await searchParams;
  const statusFilter = params.status ?? 'validation_failed';
  const db = getDirectDb();

  // The "sensitive" filter intentionally rolls up both rejected_sensitive
  // and quarantined_sensitive. Per spec: "Sensitive rejected/quarantined
  // candidates must not appear in this standard queue." We expose them
  // ONLY when the admin explicitly asks for the sensitive tab.
  const filterSql =
    statusFilter === 'all'
      ? sql`WHERE status NOT IN ('rejected_sensitive','quarantined_sensitive')`
      : statusFilter === 'sensitive'
        ? sql`WHERE status IN ('rejected_sensitive','quarantined_sensitive')`
        : sql`WHERE status = ${statusFilter}`;

  const [rowsResult, statusCountsResult] = await Promise.all([
    db.execute(sql`
      SELECT
        c.id, c.status, c.claim_type, c.summary,
        c.impact_score, c.confidence_score, c.domains, c.stance,
        c.requires_review, c.review_reason, c.validation_error,
        c.promoted_to_claim_id, c.duplicate_of_claim_id,
        c.created_at, c.validated_at, c.promoted_at,
        (
          SELECT COUNT(*)
          FROM extraction_validation_results vr
          WHERE vr.candidate_id = c.id AND vr.status IN ('fail','circuit_breaker')
        ) AS validation_failures
      FROM extraction_candidates c
      ${filterSql}
      ORDER BY c.created_at DESC
      LIMIT 100
    `),
    db.execute(sql`
      SELECT status, COUNT(*) AS count FROM extraction_candidates GROUP BY status
    `),
  ]);

  const rows = [...rowsResult] as unknown as CandidateRow[];
  const statusCounts = [...statusCountsResult] as unknown as StatusCountRow[];

  const STATUS_TABS = [
    { value: 'pending_validation', label: 'Pending' },
    { value: 'validated', label: 'Validated' },
    { value: 'promoted', label: 'Promoted' },
    { value: 'duplicate', label: 'Duplicate' },
    { value: 'validation_failed', label: 'Validation failed' },
    { value: 'failed_validation_loop', label: 'Circuit broken' },
    { value: 'sensitive', label: 'Sensitive (hidden by default)' },
    { value: 'all', label: 'All (non-sensitive)' },
  ] as const;

  const totals: Record<string, number> = {};
  for (const r of statusCounts) totals[r.status] = Number(r.count);

  return (
    <div className="space-y-6">
      <header className="space-y-1">
        <h1 className="text-2xl font-semibold">Extraction candidates</h1>
        <p className="text-sm text-muted-foreground">
          Staged outputs from extraction workers (R6/R7). Candidates promote to{' '}
          <code className="rounded bg-muted px-1 py-0.5 text-xs">claims</code> only after
          deterministic validation passes. Sensitive candidates are quarantined and never
          appear in the standard queue.
        </p>
      </header>

      <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
        <MetricCard title="Pending" value={totals['pending_validation'] ?? 0} />
        <MetricCard title="Promoted" value={totals['promoted'] ?? 0} />
        <MetricCard
          title="Validation failed"
          value={totals['validation_failed'] ?? 0}
          subtitle={`${totals['failed_validation_loop'] ?? 0} circuit-broken`}
        />
        <MetricCard
          title="Sensitive quarantined"
          value={
            (totals['rejected_sensitive'] ?? 0) + (totals['quarantined_sensitive'] ?? 0)
          }
        />
      </div>

      <div className="flex flex-wrap gap-2 text-sm">
        {STATUS_TABS.map((tab) => {
          const isActive = tab.value === statusFilter;
          return (
            <a
              key={tab.value}
              href={`/admin/ai/candidates?status=${tab.value}`}
              className={`rounded px-3 py-1 ${
                isActive
                  ? 'bg-foreground text-background'
                  : 'bg-muted text-muted-foreground hover:text-foreground'
              }`}
            >
              {tab.label}
            </a>
          );
        })}
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-base">{rows.length} candidate{rows.length === 1 ? '' : 's'}</CardTitle>
        </CardHeader>
        <CardContent>
          {rows.length === 0 ? (
            <p className="text-sm text-muted-foreground">No candidates match the current filter.</p>
          ) : (
            <div className="space-y-3">
              {rows.map((r) => {
                const domains = Array.isArray(r.domains) ? (r.domains as string[]) : [];
                return (
                  <div key={r.id} className="rounded border bg-card p-3">
                    <div className="flex items-start justify-between gap-3">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 text-xs">
                          <span className={`rounded px-1.5 py-0.5 ${statusBadge(r.status)}`}>
                            {r.status}
                          </span>
                          <span className="font-mono text-muted-foreground">{r.claim_type}</span>
                          <span className="text-muted-foreground">
                            impact {r.impact_score}/10
                          </span>
                          {r.confidence_score != null && (
                            <span className="text-muted-foreground">
                              confidence {r.confidence_score}/10
                            </span>
                          )}
                          {r.stance && (
                            <span className="text-muted-foreground">stance: {r.stance}</span>
                          )}
                        </div>
                        <p className="mt-1 text-sm">{r.summary}</p>
                   …146 tokens truncated…ror && (
                          <div className="mt-2 rounded border-l-2 border-red-400 bg-red-50 p-2 text-xs">
                            <div className="font-semibold text-red-800">
                              Validation error
                              {r.validation_failures > 0 && (
                                <span className="ml-1 text-red-700">
                                  ({r.validation_failures} failed check
                                  {r.validation_failures === 1 ? '' : 's'})
                                </span>
                              )}
                            </div>
                            <div className="text-red-900">{r.validation_error}</div>
                          </div>
                        )}
                        {r.review_reason && (
                          <div className="mt-2 text-xs text-muted-foreground italic">
                            Review requested: {r.review_reason}
                          </div>
                        )}
                      </div>
                      <div className="text-right text-xs text-muted-foreground">
                        <div className="font-mono">{r.id.slice(0, 8)}…</div>
                        <div>{new Date(r.created_at).toLocaleString()}</div>
                        {r.promoted_to_claim_id && (
                          <div className="mt-1">
                            → <span className="font-mono">{r.promoted_to_claim_id.slice(0, 8)}…</span>
                          </div>
                        )}
                        {r.duplicate_of_claim_id && (
                          <div className="mt-1">
                            ⊃ <span className="font-mono">{r.duplicate_of_claim_id.slice(0, 8)}…</span>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

// R10.5 — One proposal card. Compact summary + structured payload preview
// + approve/reject controls (when pending).

import { useState, useTransition } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  approveTaxonomyProposal,
  rejectTaxonomyProposal,
} from '../../_actions';

type ProposalCardProps = {
  proposal: {
    id: string;
    proposal_type: string;
    payload: unknown;
    status: string;
    reviewed_at: string | null;
    created_at: string;
    reviewer_name: string | null;
  };
};

type ProposalPayload = {
  proposedId?: string;
  proposedName?: string;
  oneSentencePurpose?: string;
  proposalReason?: string;
  boundaryRules?: {
    belongsHere?: string[];
    doesNotBelongHere?: string[];
    commonEntityHints?: Array<{ entityType: string; canonicalValue: string }>;
    defaultExcludedDocumentClasses?: string[];
    neighboringDomainIds?: string[];
  };
  representativeEvidence?: Array<{
    sourceType: string;
    sourceId: string;
    shortSnippet: string;
    whyRepresentative?: string;
  }>;
  affectedCounts?: Record<string, number>;
  suggestedRetrievalExclusions?: string[];
  recommendedAction?: string;
  recommendedActionReason?: string;
  confidence?: number;
  rollbackPreview?: string;
};

function statusBadge(status: string) {
  const map: Record<string, string> = {
    pending: 'bg-yellow-100 text-yellow-800',
    approved: 'bg-green-100 text-green-800',
    rejected: 'bg-red-100 text-red-800',
  };
  return map[status] ?? 'bg-muted';
}

export function ProposalCard({ proposal }: ProposalCardProps) {
  const payload = (proposal.payload ?? {}) as ProposalPayload;
  const [isPending, startTransition] = useTransition();
  const [error, setError] = useState<string | null>(null);
  const [note, setNote] = useState('');

  const onApprove = () => {
    setError(null);
    startTransition(async () => {
      try {
        await approveTaxonomyProposal(proposal.id, note.trim() || null);
        setNote('');
      } catch (e) {
        setError(e instanceof Error ? e.message : String(e));
      }
    });
  };

  const onReject = () => {
    if (!note.trim()) {
      setError('A rejection reason is required.');
      return;
    }
    setError(null);
    startTransition(async () => {
      try {
        await rejectTaxonomyProposal(proposal.id, note.trim());
        setNote('');
      } catch (e) {
        setError(e instanceof Error ? e.message : String(e));
      }
    });
  };

  const isPendingReview = proposal.status === 'pending';
  const evidence = payload.representativeEvidence ?? [];
  const entityHints = payload.boundaryRules?.commonEntityHints ?? [];

  return (
    <Card>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="text-base">
            <span className="font-mono text-xs text-muted-foreground">
              {proposal.proposal_type}
            </span>{' '}
            {payload.proposedName ?? '(unnamed)'}
            {payload.proposedId && (
              <span className="ml-2 font-mono text-xs text-muted-foreground">
                ({payload.proposedId})
              </span>
            )}
          </CardTitle>
          <span className={`rounded px-1.5 py-0.5 text-xs ${statusBadge(proposal.status)}`}>
            {proposal.status}
          </span>
        </div>
        {payload.oneSentencePurpose && (
          <p className="mt-1 text-sm">{payload.oneSentencePurpose}</p>
        )}
      </CardHeader>
      <CardContent className="space-y-3 text-xs">
        {payload.proposalReason && (
          <div>
            <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">
              Why proposed
            </div>
            <div className="italic">{payload.proposalReason}</div>
          </div>
        )}

        {payload.boundaryRules?.belongsHere && payload.boundaryRules.belongsHere.length > 0 && (
          <ChipList
            label="Belongs here"
            tone="green"
            items={payload.boundaryRules.belongsHere}
          />
        )}
        {payload.boundaryRules?.doesNotBelongHere &&
          payload.boundaryRules.doesNotBelongHere.length > 0 && (
            <ChipList
              label="Does NOT belong here"
              tone="red"
              items={payload.boundaryRules.doesNotBelongHere}
            />
          )}
        {entityHints.length > 0 && (
          <ChipList
            label="Common entities"
            tone="neutral"
            items={entityHints.map((e) => `${e.entityType}: ${e.canonicalValue}`)}
          />
        )}
        {payload.boundaryRules?.defaultExcludedDocumentClasses &&
          payload.boundaryRules.defaultExcludedDocumentClasses.length > 0 && (
            <ChipList
              label="Default excluded document classes"
              tone="amber"
              items={payload.boundaryRules.defaultExcludedDocumentClasses}
            />
          )}
        {payload.boundaryRules?.neighboringDomainIds &&
          payload.boundaryRules.neighboringDomainIds.length > 0 && (
            <ChipList
              label="Neighboring domains"
              tone="neutral"
              items={payload.boundaryRules.neighboringDomainIds}
            />
          )}

        {evidence.length > 0 && (
          <div>
            <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">
              Representative evidence ({evidence.length})
            </div>
            <ul className="space-y-1">
              {evidence.slice(0, 5).map((e, i) => (
                <li key={i} className="rounded border-l-2 border-muted bg-muted/30 px-2 py-1">
                  <span className="font-mono text-[10px] text-muted-foreground">
                    {e.sourceType}:{e.sourceId.slice(0, 8)}…
                  </span>
                  <div className="mt-0.5 italic">"{e.shortSnippet}"</div>
                  {e.whyRepresentative && (
                    <div className="text-[10px] text-muted-foreground">{e.whyRepresentative}</div>
                  )}
                </li>
              ))}
            </ul>
          </div>
        )}

        {payload.affectedCounts && Object.keys(payload.affectedCounts).length > 0 && (
          <div>
            <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">
              Affected counts
            </div>
            <div className="flex gap-2 text-xs">
              {Object.entries(payload.affectedCounts).map(([k, v]) => (
                <span key={k} className="rounded bg-muted px-1.5 py-0.5 text-muted-foreground">
                  {k}: {v}
                </span>
              ))}
            </div>
          </div>
        )}

        <div className="flex items-center justify-between border-t pt-2 text-[10px] text-muted-foreground">
          <span>
            Created {new Date(proposal.created_at).toLocaleString()}
            {proposal.reviewer_name && proposal.reviewed_at && (
              <>
                {' '}
                · Reviewed by <strong>{proposal.reviewer_name}</strong>{' '}
                {new Date(proposal.reviewed_at).toLocaleString()}
              </>
            )}
          </span>
          {payload.recommendedAction && (
            <span>
              Recommended:{' '}
              <strong className="text-foreground">{payload.recommendedAction}</strong>
              {payload.confidence != null && ` (conf ${payload.confidence.toFixed(2)})`}
            </span>
          )}
        </div>

        {isPendingReview && (
          <div className="space-y-2 border-t pt-3">
            <Input
              type="text"
              placeholder="Reviewer note (required for reject; optional for approve)"
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="text-xs"
            />
            <div className="flex gap-2">
              <Button
                type="button"
                size="sm"
                onClick={onApprove}
                disabled={isPending}
                className="bg-green-700 hover:bg-green-800"
              >
                {isPending ? 'Working…' : 'Approve'}
              </Button>
              <Button
                type="button"
                size="sm"
                variant="outline"
                onClick={onReject}
                disabled={isPending}
              >
                Reject
              </Button>
            </div>
            {error && (
              <div className="rounded bg-red-50 px-2 py-1 text-xs text-red-800">{error}</div>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function ChipList({
  label,
  tone,
  items,
}: {
  label: string;
  tone: 'green' | 'red' | 'amber' | 'neutral';
  items: string[];
}) {
  const colorMap: Record<typeof tone, string> = {
    green: 'bg-green-50 text-green-800',
    red: 'bg-red-50 text-red-800',
    amber: 'bg-amber-50 text-amber-800',
    neutral: 'bg-muted text-muted-foreground',
  };
  return (
    <div>
      <div className="mb-1 text-[10px] uppercase tracking-wide text-muted-foreground">{label}</div>
      <div className="flex flex-wrap gap-1">
        {items.map((it, i) => (
          <span key={`${label}-${i}`} className={`rounded px-1.5 py-0.5 ${colorMap[tone]}`}>
            {it}
          </span>
        ))}
      </div>
    </div>
  );
}

