             stagedEntityProposalIds: [] }
  }

  // 3. Race-safe existing-claim-by-hash lookup (unchanged from today)
  const existingByHash = await tx.select(...).from(claims).where(...)

  // 4. Decide with FRESH snapshot + caller's taxonomy/metadata + in-lock hash lookup
  const decision = decidePromotion({
    candidateHash,
    candidate: fresh.candidate,
    validatedEvidence: fresh.validatedEvidence,
    taxonomy: input.auxiliaryInputs?.taxonomy,
    metadata: input.auxiliaryInputs?.metadata,
    existingClaimWithSameHash: existingByHash[0] ?? null,
  })

  // 5. Stage entity_proposals + apply decision (unchanged branches below)
  // ...
})
