  234: export async function approveEntityProposal(
  235:   proposalId: string,
  236:   // Allow the admin to refine the canonical value at approval time.
  237:   finalCanonicalValue?: string,
  238:   // Optional display label (defaults to canonical value).
  239:   displayLabel?: string,
  240: ) {
  241:   const me = await requireAdmin();
  242:   const db = getDirectDb();
  243: 
  244:   await db.transaction(async (tx) => {
  245:     const [proposal] = await tx
  246:       .select()
  247:       .from(entityProposals)
  248:       .where(and(eq(entityProposals.id, proposalId), eq(entityProposals.status, 'pending')))
  249:       .limit(1);
  250:     if (!proposal) throw new Error('Entity proposal not found or already reviewed');
  251: 
  252:     const canonicalValue = (finalCanonicalValue ?? proposal.proposedCanonicalValue).trim();
  253:     if (!canonicalValue) {
  254:       throw new Error('canonical value must not be empty');
  255:     }
  256: 
  257:     const aliases = Array.isArray(proposal.rawStringsObserved)
  258:       ? (proposal.rawStringsObserved as string[]).filter((s) => s && s !== canonicalValue)
  259:       : [];
  260: 
  261:     const [insertedEntity] = await tx
  262:       .insert(entities)
  263:       .values({
  264:         entityType: proposal.proposedEntityType,
  265:         canonicalValue,
  266:         displayLabel: displayLabel ?? canonicalValue,
  267:         aliases,
  268:         domainHints: proposal.proposedDomainHints ?? [],
  269:       })
  270:       .onConflictDoNothing()
  271:       .returning({ id: entities.id });
  272: 
  273:     // If onConflictDoNothing returned no row, that means an entity with the
  274:     // same (entity_type, canonical_value) already exists. Look it up so we
  275:     // can merge against it instead of creating a duplicate.
  276:     let entityId = insertedEntity?.id;
  277:     if (!entityId) {
  278:       const [existing] = await tx
  279:         .select({ id: entities.id })
  280:         .from(entities)
  281:         .where(
  282:           and(
  283:             eq(entities.entityType, proposal.proposedEntityType),
  284:             eq(entities.canonicalValue, canonicalValue),
  285:           ),
  286:         )
  287:         .limit(1);
  288:       if (!existing) throw new Error('failed to resolve entity after onConflictDoNothing');
  289:       entityId = existing.id;
  290:     }
  291: 
  292:     await tx
  293:       .update(entityProposals)
  294:       .set({
  295:         status: insertedEntity ? 'approved' : 'merged_into_existing',
  296:         mergedIntoEntityId: entityId,
  297:         reviewedByEmployeeId: me.id,
  298:         reviewedAt: new Date(),
  299:       })
  300:       .where(eq(entityProposals.id, proposalId));
  301: 
  302:     await tx.insert(taxonomyChangeLog).values({
  303:       changeType: insertedEntity ? 'create_entity_from_proposal' : 'merge_entity_proposal',
  304:       beforeState: {
  305:         proposalId,
  306:         proposedEntityType: proposal.proposedEntityType,
  307:         proposedCanonicalValue: proposal.proposedCanonicalValue,
  308:       },
  309:       afterState: { entityId, finalCanonicalValue: canonicalValue },
  310:       reason: null,
  311:       approvedByEmployeeId: me.id,
  312:     });
  313:   });
  314: 
  315:   revalidatePath('/admin/taxonomy/entity-proposals');
  316:   revalidatePath('/admin/taxonomy/entities');
  317:   revalidatePath('/admin/taxonomy/change-log');
  318: }

